14	const decomposerPromptSource = "bead-lifecycle-decompose"
15	const decomposerDefaultTimeout = 8 * time.Minute
16	
17	// DecomposeResult is the outcome of a runDecomposer invocation.
18	type DecomposeResult struct {
19		Failed   bool
20		Reason   string
21		ChildIDs []string
22		CostUSD  float64
23	}
24	
25	type decomposerChild struct {
26		Title       string   `json:"title"`
27		Description string   `json:"description"`
28		Acceptance  string   `json:"acceptance"`
29		Labels      []string `json:"labels,omitempty"`
30	}
31	
32	type decomposerEventBody struct {
33		ChildIDs []string `json:"child_ids"`
34		CostUSD  float64  `json:"cost_usd,omitempty"`
35	}
36	
37	// NewDecomposePostLadderExhaustionHook creates a PostLadderExhaustionHook that
38	// dispatches runDecomposer for TooLarge failure class.
39	func NewDecomposePostLadderExhaustionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string) PostLadderExhaustionHook {
40		return func(ctx context.Context, beadID string, failureClass RecoveryFailureClass) (*PostLadderExhaustionResult, error) {
41			if failureClass != TooLarge {
42				return &PostLadderExhaustionResult{Attempted: false}, nil
43			}
44			result := runDecomposer(ctx, store, runner, rcfg, projectRoot, beadID)
45			if result.Failed {
46				return &PostLadderExhaustionResult{
47					Attempted: true,
48					Succeeded: false,
49					Path:      Decompose,
50				}, nil
51			}
52			return &PostLadderExhaustionResult{
53				Attempted: true,
54				Succeeded: true,
55				Path:      Decompose,
56				CostUSD:   result.CostUSD,
57			}, nil
58		}
59	}
60	
61	// runDecomposer dispatches a smart+ tier agent to split the bead into child
62	// beads after the escalation ladder has been exhausted. On success, child beads
63	// are created with Parent=beadID, the parent's execution-eligible is set to
64	// false, and a "decompose-applied" event is emitted. On failure a
65	// DecomposeResult with Failed=true is returned.
66	func runDecomposer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) DecomposeResult {
67		tctx, cancel := context.WithTimeout(ctx, decomposerDefaultTimeout)
68		defer cancel()
69	
70		b, err := store.Get(beadID)
71		if err != nil {
72			return DecomposeResult{Failed: true, Reason: "store_error"}
73		}
74	
75		prompt, err := buildDecomposerPrompt(store, b)
76		if err != nil {
77			return DecomposeResult{Failed: true, Reason: "prompt_error"}
78		}
79	
80		runtime := AgentRunRuntime{
81			Prompt:           prompt,
82			WorkDir:          projectRoot,
83			PromptSource:     decomposerPromptSource,
84			ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
85			ClearRoutingPins: true,
86			ClearProfile:     true,
87			ClearMinPower:    true,
88			ClearMaxPower:    true,
89		}
90	
91		result, err := dispatchViaResolvedConfig(tctx, projectRoot, nil, runner, rcfg, runtime)
92		if err != nil {
93			if tctx.Err() != nil {
94				return DecomposeResult{Failed: true, Reason: "timeout"}
95			}
96			return DecomposeResult{Failed: true, Reason: "dispatch_error"}
97		}
98	
99		output := strings.TrimSpace(result.CondensedOutput)
100		if output == "" {
101			output = strings.TrimSpace(result.Output)
102		}
103		if output == "" {
104			return DecomposeResult{Failed: true, Reason: "empty_output"}
105		}
106	
107		children, ok := parseDecomposerOutput(output)
108		if !ok {
109			return DecomposeResult{Failed: true, Reason: "invalid_output"}
110		}
111	
112		if len(children) < 1 || len(children) > 5 {
113			return DecomposeResult{Failed: true, Reason: "invalid_count"}
114		}
115	
116		for _, child := range children {
117			if strings.TrimSpace(child.Title) == "" ||
118				strings.TrimSpace(child.Description) == "" ||
119				strings.TrimSpace(child.Acceptance) == "" {
120				return DecomposeResult{Failed: true, Reason: "malformed_child"}
121			}
122		}
123	
124		childIDs := make([]string, 0, len(children))
125		for _, child := range children {
126			nb := &bead.Bead{
127				Title:       strings.TrimSpace(child.Title),
128				Description: strings.TrimSpace(child.Description),
129				Acceptance:  strings.TrimSpace(child.Acceptance),
130				Labels:      append([]string(nil), child.Labels...),
131				Parent:      beadID,
132			}
133			if err := store.Create(nb); err != nil {
134				return DecomposeResult{Failed: true, Reason: "create_error"}
135			}
136			childIDs = append(childIDs, nb.ID)
137		}
138	
139		_ = store.Update(beadID, func(b *bead.Bead) {
140			ensureBeadExtra(b)
141			b.Extra[bead.ExtraExecutionElig] = false
142		})
143	
144		body, _ := json.Marshal(decomposerEventBody{
145			ChildIDs: childIDs,
146			CostUSD:  result.CostUSD,
147		})
148		_ = store.AppendEvent(beadID, bead.BeadEvent{
149			Kind:      "decompose-applied",
150			Summary:   fmt.Sprintf("decomposed into %s", strings.Join(childIDs, ", ")),
151			Body:      string(body),
152			Actor:     "ddx agent execute-loop",
153			Source:    "ddx agent execute-loop",
154			CreatedAt: time.Now().UTC(),
155		})
156	
157		return DecomposeResult{
158			Failed:   false,
159			ChildIDs: childIDs,
160			CostUSD:  result.CostUSD,
161		}
162	}
163	
164	func buildDecomposerPrompt(store ExecuteBeadLoopStore, b *bead.Bead) (string, error) {
165		type failureEntry struct {
166			Summary string `json:"summary"`
167			Body    string `json:"body,omitempty"`
168		}
169		type envelope struct {
170			Title          string         `json:"title"`
171			Description    string         `json:"description"`
172			Acceptance     string         `json:"acceptance"`
173			FailureHistory []failureEntry `json:"failure_history"`
174		}
175	
176		env := envelope{
177			Title:       strings.TrimSpace(b.Title),
178			Description: strings.TrimSpace(b.Description),
179			Acceptance:  strings.TrimSpace(b.Acceptance),
180		}
181	
182		if events, err := store.Events(b.ID); err == nil {
183			for i := len(events) - 1; i >= 0 && len(env.FailureHistory) < 5; i-- {
184				ev := events[i]
185				switch ev.Kind {
186				case "bead.result", "execute-bead", "per-bead-budget-exhausted":
187				default:
188					continue
189				}
190				env.FailureHistory = append(env.FailureHistory, failureEntry{
191					Summary: strings.TrimSpace(ev.Summary),
192					Body:    strings.TrimSpace(ev.Body),
193				})
194			}
195		}
196	
197		body, err := json.MarshalIndent(env, "", "  ")
198		if err != nil {
199			return "", fmt.Errorf("decomposer: encode prompt: %w", err)
200		}
201	
202		var sb strings.Builder
203		sb.WriteString("MODE: decompose\n")
204		sb.WriteString("You are splitting a bead that is too large into 2-5 independently executable child beads.\n")
205		sb.WriteString("Each child must have a self-contained description, 3-6 numbered ACs with at least one named test function.\n")
206		sb.WriteString("Return exactly one JSON array of child spec objects: [{\"title\":...,\"description\":...,\"acceptance\":...,\"labels\":[...]}]\n")
207		sb.WriteString("Do not include prose or markdown; return only the JSON array.\n\n")
208		sb.WriteString("```json\n")
209		sb.Write(body)
210		sb.WriteString("\n```\n")
211		return sb.String(), nil
212	}
213	
214	// parseDecomposerOutput extracts a JSON array of child specs from agent output.
215	func parseDecomposerOutput(output string) ([]decomposerChild, bool) {
216		if c, ok := lastFencedBlock(output, "json"); ok {
217			var children []decomposerChild
218			if err := json.Unmarshal([]byte(strings.TrimSpace(c)), &children); err == nil {
219				return children, true
220			}
221		}
222		if c, ok := lastFencedBlock(output, ""); ok {
223			trimmed := strings.TrimSpace(c)
224			if strings.HasPrefix(trimmed, "[") {
225				var children []decomposerChild
226				if err := json.Unmarshal([]byte(trimmed), &children); err == nil {
227					return children, true
228				}
229			}
230		}
231		// Scan for first '[' and balance brackets to find a raw JSON array.
232		start := strings.Index(output, "[")
233		if start == -1 {
234			return nil, false
235		}
236		depth := 0
237		for i := start; i < len(output); i++ {
238			switch output[i] {
239			case '[':
240				depth++
241			case ']':
242				depth--
243				if depth == 0 {
244					var children []decomposerChild
245					if err := json.Unmarshal([]byte(output[start:i+1]), &children); err == nil {
246						return children, true
247					}
248					return nil, false
249				}
250			}
251		}
252		return nil, false
253	}
