14	const reframerPromptSource = "bead-lifecycle-reframe"
15	const reframerDefaultTimeout = 5 * time.Minute
16	
17	// ReframeResult is the outcome of a runReframer invocation.
18	type ReframeResult struct {
19		Failed         bool
20		Reason         string
21		NewDescription string
22		NewAcceptance  string
23		CostUSD        float64
24	}
25	
26	type reframerOutput struct {
27		Description *string `json:"description"`
28		Acceptance  *string `json:"acceptance"`
29	}
30	
31	type reframerEventBody struct {
32		CostUSD            float64 `json:"cost_usd,omitempty"`
33		DescriptionChanged bool    `json:"description_changed"`
34		AcceptanceChanged  bool    `json:"acceptance_changed"`
35	}
