64	// runReframer dispatches a smart+ tier agent to rewrite the bead's description
65	// and acceptance criteria after the escalation ladder has been exhausted.
66	// On success, the bead description/AC are updated, the
67	// consecutive_ladder_exhaustions counter is cleared, and a "reframe-applied"
68	// event is emitted. On failure a ReframeResult with Failed=true is returned.
69	func runReframer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) ReframeResult {
70		tctx, cancel := context.WithTimeout(ctx, reframerDefaultTimeout)
71		defer cancel()
72	
73		b, err := store.Get(beadID)
74		if err != nil {
75			return ReframeResult{Failed: true, Reason: "store_error"}
76		}
77	
78		prompt, err := buildReframerPrompt(store, b)
79		if err != nil {
80			return ReframeResult{Failed: true, Reason: "prompt_error"}
81		}
82	
83		runtime := AgentRunRuntime{
84			Prompt:           prompt,
85			WorkDir:          projectRoot,
86			PromptSource:     reframerPromptSource,
87			ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
88			ClearRoutingPins: true,
89			ClearProfile:     true,
90			ClearMinPower:    true,
91			ClearMaxPower:    true,
92		}
93	
94		result, err := dispatchViaResolvedConfig(tctx, projectRoot, nil, runner, rcfg, runtime)
95		if err != nil {
96			if tctx.Err() != nil {
97				return ReframeResult{Failed: true, Reason: "timeout"}
98			}
99			return ReframeResult{Failed: true, Reason: "dispatch_error"}
100		}
101	
102		output := strings.TrimSpace(result.CondensedOutput)
103		if output == "" {
104			output = strings.TrimSpace(result.Output)
105		}
106		if output == "" {
107			return ReframeResult{Failed: true, Reason: "empty_output"}
108		}
109	
110		candidate, ok := extractJSONCandidate(output)
111		if !ok {
112			return ReframeResult{Failed: true, Reason: "invalid_output"}
113		}
114	
115		var parsed reframerOutput
116		if err := json.Unmarshal([]byte(candidate), &parsed); err != nil {
117			return ReframeResult{Failed: true, Reason: "invalid_output"}
118		}
119		if parsed.Description == nil && parsed.Acceptance == nil {
120			return ReframeResult{Failed: true, Reason: "invalid_output"}
121		}
122	
123		current, err := store.Get(beadID)
124		if err != nil {
125			return ReframeResult{Failed: true, Reason: "store_error"}
126		}
127	
128		descChanged := parsed.Description != nil &&
129			strings.TrimSpace(*parsed.Description) != strings.TrimSpace(current.Description)
130		accChanged := parsed.Acceptance != nil &&
131			strings.TrimSpace(*parsed.Acceptance) != strings.TrimSpace(current.Acceptance)
132	
133		if !descChanged && !accChanged {
134			return ReframeResult{Failed: true, Reason: "noop_edits"}
135		}
136	
137		var changedFields []string
138		var rewrite PreClaimIntakeRewrite
139		if descChanged {
140			changedFields = append(changedFields, "description")
141			rewrite.Description = strings.TrimSpace(*parsed.Description)
142		}
143		if accChanged {
144			changedFields = append(changedFields, "acceptance")
145			rewrite.Acceptance = strings.TrimSpace(*parsed.Acceptance)
146		}
147		rewrite.ChangedFields = changedFields
148	
149		intake := PreClaimIntakeResult{
150			Outcome: PreClaimIntakeActionableButRewritten,
151			Detail:  "reframer rewrote bead after exhaustion",
152			Rewrite: rewrite,
153		}
154	
155		if err := applyPreClaimIntakeRewrite(store, beadID, "ddx agent execute-loop", intake, time.Now()); err != nil {
156			return ReframeResult{Failed: true, Reason: "apply_error"}
157		}
158	
159		_ = store.Update(beadID, func(b *bead.Bead) {
160			ensureBeadExtra(b)
161			delete(b.Extra, consecutiveLadderExhaustionsKey)
162		})
163	
164		body, _ := json.Marshal(reframerEventBody{
165			CostUSD:            result.CostUSD,
166			DescriptionChanged: descChanged,
167			AcceptanceChanged:  accChanged,
168		})
169		_ = store.AppendEvent(beadID, bead.BeadEvent{
170			Kind:      "reframe-applied",
171			Summary:   strings.Join(changedFields, ","),
172			Body:      string(body),
173			Actor:     "ddx agent execute-loop",
174			Source:    "ddx agent execute-loop",
175			CreatedAt: time.Now().UTC(),
176		})
177	
178		out := ReframeResult{
179			Failed:  false,
180			CostUSD: result.CostUSD,
181		}
182		if descChanged {
183			out.NewDescription = rewrite.Description
184		}
185		if accChanged {
186			out.NewAcceptance = rewrite.Acceptance
187		}
188		return out
189	}
