192		type failureEntry struct {
193			Summary string `json:"summary"`
194			Body    string `json:"body,omitempty"`
195		}
196		type envelope struct {
197			Title          string         `json:"title"`
198			Description    string         `json:"description"`
199			Acceptance     string         `json:"acceptance"`
200			FailureHistory []failureEntry `json:"failure_history"`
201		}
202	
203		env := envelope{
204			Title:       strings.TrimSpace(b.Title),
205			Description: strings.TrimSpace(b.Description),
206			Acceptance:  strings.TrimSpace(b.Acceptance),
207		}
