233		sb.WriteString("Preservation rules: governing artifact references (FEAT-NNN, ADR-NNN), named test functions (TestFoo), file:line evidence, dependency IDs (ddx-XXXXXXXX), and NON-SCOPE bullets must appear in any rewrite.\n")
234		sb.WriteString("Return exactly one JSON object: {\"description\": string|null, \"acceptance\": string|null}\n")
235		sb.WriteString("Use null to leave a field unchanged. At least one field must be non-null and meaningfully changed.\n")
236		sb.WriteString("Do not include prose or markdown; return only the JSON object.\n\n")
237		sb.WriteString("```json\n")
238		sb.Write(body)
239		sb.WriteString("\n```\n")
240		return sb.String(), nil
241	}
