1	package cmd
2	
3	import (
4		"context"
5		"errors"
6		"fmt"
7		"os"
8		"strings"
9	
10		"github.com/DocumentDrivenDX/ddx/internal/agent"
11		tierescalation "github.com/DocumentDrivenDX/ddx/internal/agent/escalation"
12		"github.com/DocumentDrivenDX/ddx/internal/bead"
13		policyescalation "github.com/DocumentDrivenDX/ddx/internal/escalation"
14	)
15	
16	type escalationFloorFinder interface {
17		Next(actualPower int) (int, error)
18	}
19	
20	func isBudgetExhaustedFailure(report agent.ExecuteBeadReport) bool {
21		return strings.Contains(report.Detail, agent.RateLimitBudgetExhaustedReason)
22	}
23	
24	func nextEscalationFloor(l escalationFloorFinder, actualPower int) (int, error) {
25		if l == nil {
26			return 0, tierescalation.ErrLadderExhausted
27		}
28		floor := actualPower
29		for {
30			next, err := l.Next(floor)
31			if err == nil {
32				return next, nil
33			}
34			var nvp *tierescalation.NoViableProviderError
35			if errors.As(err, &nvp) {
36				floor = nvp.Floor
37				continue
38			}
39			return 0, err
40		}
41	}
42	
43	func highestViableEscalationFloor(l escalationFloorFinder) (int, error) {
44		if l == nil {
45			return 0, tierescalation.ErrLadderExhausted
46		}
47		floor := 0
48		highest := 0
49		for {
50			next, err := nextEscalationFloor(l, floor)
51			if err != nil {
52				if errors.Is(err, tierescalation.ErrLadderExhausted) && highest > 0 {
53					return highest, nil
54				}
55				return 0, err
56			}
57			highest = next
58			floor = next
59		}
60	}
61	
62	func investigationRetryInitialMinPower(b *bead.Bead, baseMinPower, maxPower int, ladder escalationFloorFinder) (int, agent.ExecuteBeadReport, bool) {
63		// Numeric hint: written by the no-changes smart-retry path one step at a time.
64		if floor, ok := numericTierFloorHint(b); ok {
65			if baseMinPower > floor {
66				return baseMinPower, smartRouteUnavailableReport(b, baseMinPower, maxPower, nil), true
67			}
68			if maxPower > 0 && floor >= maxPower {
69				return baseMinPower, smartRouteUnavailableReport(b, floor, maxPower, nil), true
70			}
71			return floor, agent.ExecuteBeadReport{}, false
72		}
73		// Tier-name hint: written by the review-triage path; jump to highest viable for smart.
74		if tier, ok := triageTierHint(b); ok && tier == policyescalation.TierSmart {
75			floor, err := highestViableEscalationFloor(ladder)
76			if err != nil {
77				return baseMinPower, smartRouteUnavailableReport(b, baseMinPower, maxPower, err), true
78			}
79			if baseMinPower > floor {
80				return baseMinPower, smartRouteUnavailableReport(b, baseMinPower, maxPower, nil), true
81			}
82			if maxPower > 0 && floor >= maxPower {
83				return baseMinPower, smartRouteUnavailableReport(b, floor, maxPower, nil), true
84			}
85			return floor, agent.ExecuteBeadReport{}, false
86		}
87		// Label-based tier hint: tier:hint=<name> sets the initial MinPower floor.
88		// --min-power flag composes as max(labelFloor, baseMinPower): the flag can
89		// raise the floor above the label but cannot lower it below.
90		if b != nil {
91			if tier, ok := policyescalation.ParseBeadTierHintLabel(b.Labels); ok {
92				labelFloor := resolveTierFloor(tier, ladder)
93				floor := labelFloor
94				if baseMinPower > floor {
95					floor = baseMinPower
96				}
97				if maxPower > 0 && floor >= maxPower {
98					return baseMinPower, smartRouteUnavailableReport(b, floor, maxPower, nil), true
99				}
100				return floor, agent.ExecuteBeadReport{}, false
101			} else if policyescalation.HasBeadTierHintLabel(b.Labels) {
102				fmt.Fprintf(os.Stderr, "ddx: bead %s has unrecognized tier:hint label; using default MinPower\n", b.ID)
103			}
104		}
105		return baseMinPower, agent.ExecuteBeadReport{}, false
106	}
107	
108	// resolveTierFloor maps an abstract tier to an initial MinPower floor using the
109	// escalation ladder:
110	//   - TierSmart    → highest viable floor (jump straight to the top tier)
111	//   - TierStandard → second viable floor (skip the cheapest tier)
112	//   - TierCheap    → 0 (unconstrained; same as having no label)
113	func resolveTierFloor(tier policyescalation.ModelTier, ladder escalationFloorFinder) int {
114		switch tier {
115		case policyescalation.TierSmart:
116			floor, err := highestViableEscalationFloor(ladder)
117			if err != nil {
118				return 0
119			}
120			return floor
121		case policyescalation.TierStandard:
122			first, err := nextEscalationFloor(ladder, 0)
