199	func runEscalatingSingleTierAttempts(
200		ctx context.Context,
201		initialMinPower int,
202		ladder escalationFloorFinder,
203		attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
204		recordAttempt func(agent.ExecuteBeadReport),
205		perBeadTracker *policyescalation.PerBeadCostTracker,
206	) (agent.ExecuteBeadReport, error) {
207		minPower := initialMinPower
208		for {
209			report, err := attempt(ctx, minPower)
210			if recordAttempt != nil && report.BeadID != "" {
211				recordAttempt(report)
212			}
213			if perBeadTracker != nil {
214				perBeadTracker.Add(report.Harness, report.CostUSD)
215			}
216			if err != nil {
217				return report, err
218			}
219			if report.Disrupted || isBudgetExhaustedFailure(report) || !policyescalation.ShouldEscalate(report.Status) || policyescalation.IsInfrastructureFailure(report.Status, report.Detail) {
220				return report, nil
221			}
222			// Check per-bead budget before escalating to the next tier.
223			if perBeadTracker != nil {
224				if detail, tripped := perBeadTracker.Tripped(); tripped {
225					report.Status = agent.ExecuteBeadStatusExecutionFailed
226					report.Detail = detail
227					report.CostUSD = perBeadTracker.Spent() // total for this bead
228					return report, nil
229				}
230			}
231			basis := minPower
232			if report.ActualPower > 0 {
233				basis = report.ActualPower
234			}
235			nextPower, nextErr := nextEscalationFloor(ladder, basis)
236			if nextErr != nil {
237				return report, nil
238			}
239			minPower = nextPower
240		}
241	}
