61	// runDecomposer dispatches a smart+ tier agent to split the bead into child
62	// beads after the escalation ladder has been exhausted. On success, child beads
63	// are created with Parent=beadID, the parent's execution-eligible is set to
64	// false, and a "decompose-applied" event is emitted. On failure a
65	// DecomposeResult with Failed=true is returned.
66	func runDecomposer(ctx context.Context, store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, beadID string) DecomposeResult {
67		tctx, cancel := context.WithTimeout(ctx, decomposerDefaultTimeout)
68		defer cancel()
69	
70		b, err := store.Get(beadID)
71		if err != nil {
72			return DecomposeResult{Failed: true, Reason: "store_error"}
73		}
74	
75		prompt, err := buildDecomposerPrompt(store, b)
76		if err != nil {
77			return DecomposeResult{Failed: true, Reason: "prompt_error"}
78		}
79	
80		runtime := AgentRunRuntime{
81			Prompt:           prompt,
82			WorkDir:          projectRoot,
83			PromptSource:     decomposerPromptSource,
84			ProfileOverride:  selectProfileForDispatch(tctx, projectRoot, nil, runner, SelectStrongestProfile),
85			ClearRoutingPins: true,
86			ClearProfile:     true,
87			ClearMinPower:    true,
88			ClearMaxPower:    true,
89		}
90	
91		result, err := dispatchViaResolvedConfig(tctx, projectRoot, nil, runner, rcfg, runtime)
92		if err != nil {
93			if tctx.Err() != nil {
94				return DecomposeResult{Failed: true, Reason: "timeout"}
95			}
96			return DecomposeResult{Failed: true, Reason: "dispatch_error"}
97		}
98	
99		output := strings.TrimSpace(result.CondensedOutput)
100		if output == "" {
101			output = strings.TrimSpace(result.Output)
102		}
103		if output == "" {
104			return DecomposeResult{Failed: true, Reason: "empty_output"}
105		}
106	
107		children, ok := parseDecomposerOutput(output)
108		if !ok {
109			return DecomposeResult{Failed: true, Reason: "invalid_output"}
110		}
111	
112		if len(children) < 1 || len(children) > 5 {
113			return DecomposeResult{Failed: true, Reason: "invalid_count"}
114		}
115	
116		for _, child := range children {
117			if strings.TrimSpace(child.Title) == "" ||
118				strings.TrimSpace(child.Description) == "" ||
119				strings.TrimSpace(child.Acceptance) == "" {
120				return DecomposeResult{Failed: true, Reason: "malformed_child"}
121			}
122		}
123	
124		childIDs := make([]string, 0, len(children))
125		for _, child := range children {
126			nb := &bead.Bead{
127				Title:       strings.TrimSpace(child.Title),
128				Description: strings.TrimSpace(child.Description),
129				Acceptance:  strings.TrimSpace(child.Acceptance),
130				Labels:      append([]string(nil), child.Labels...),
131				Parent:      beadID,
132			}
133			if err := store.Create(nb); err != nil {
134				return DecomposeResult{Failed: true, Reason: "create_error"}
135			}
136			childIDs = append(childIDs, nb.ID)
137		}
138	
139		_ = store.Update(beadID, func(b *bead.Bead) {
140			ensureBeadExtra(b)
141			b.Extra[bead.ExtraExecutionElig] = false
142		})
143	
144		body, _ := json.Marshal(decomposerEventBody{
145			ChildIDs: childIDs,
146			CostUSD:  result.CostUSD,
147		})
148		_ = store.AppendEvent(beadID, bead.BeadEvent{
149			Kind:      "decompose-applied",
150			Summary:   fmt.Sprintf("decomposed into %s", strings.Join(childIDs, ", ")),
151			Body:      string(body),
152			Actor:     "ddx agent execute-loop",
153			Source:    "ddx agent execute-loop",
154			CreatedAt: time.Now().UTC(),
155		})
156	
157		return DecomposeResult{
158			Failed:   false,
159			ChildIDs: childIDs,
160			CostUSD:  result.CostUSD,
161		}
162	}
