105	// newAgentWorkersStopCommand wires the `ddx agent workers stop` subcommand.
106	// Targeting modes are mutually exclusive:
107	//
108	//	ddx agent workers stop <worker-id>     — one worker by id
109	//	ddx agent workers stop --all-over <d>  — every running worker older than <d>
110	//	ddx agent workers stop --state <state> — every worker in <state>
111	//	ddx agent workers stop --bead <id>     — the worker assigned to <bead-id>
112	//
113	// Each match POSTs /api/agent/workers/{id}/stop on the running ddx server,
114	// which triggers the graceful SIGTERM → grace → SIGKILL path in
115	// WorkerManager.Stop. Returns a non-zero exit code if any target fails.
116	func (f *CommandFactory) newAgentWorkersStopCommand() *cobra.Command {
117		cmd := &cobra.Command{
118			Use:   "stop [worker-id]",
119			Short: "Gracefully stop running agent workers",
120			Long: `Gracefully terminate one or more running agent workers.
121	
122	The server sends SIGTERM to the worker's process group, waits for the configured
123	grace window, and escalates to SIGKILL if the leader is still alive. The worker's
124	bead claim is released and a bead.stopped event is appended to the tracker before
125	the kill, so claims are not leaked even when the full grace elapses.
126	
127	Examples:
128	  ddx agent workers stop worker-20260418T100000-abcd
129	  ddx agent workers stop --all-over 1h
130	  ddx agent workers stop --state running
131	  ddx agent workers stop --bead ddx-abc12345`,
132			RunE: f.runAgentWorkersStop,
133		}
134		cmd.Flags().Duration("all-over", 0, "Stop every running worker older than this duration")
135		cmd.Flags().String("state", "", "Stop every worker in the given state (e.g. running)")
136		cmd.Flags().String("bead", "", "Stop the worker assigned to the given bead id")
137		cmd.Flags().String("project", "", "Project root to query (default: detected from CWD)")
138		cmd.Flags().Bool("json", false, "Emit one JSON object per worker acted on")
139		return cmd
140	}
