142	func (f *CommandFactory) runAgentWorkersStop(cmd *cobra.Command, args []string) error {
143		allOver, _ := cmd.Flags().GetDuration("all-over")
144		stateFilter, _ := cmd.Flags().GetString("state")
145		beadFilter, _ := cmd.Flags().GetString("bead")
146		projectFlag, _ := cmd.Flags().GetString("project")
147		asJSON, _ := cmd.Flags().GetBool("json")
148	
149		// Enforce that the operator picks exactly one targeting mode.
150		modes := 0
151		if len(args) > 0 {
152			modes++
153		}
154		if allOver > 0 {
155			modes++
156		}
157		if stateFilter != "" {
158			modes++
159		}
160		if beadFilter != "" {
161			modes++
162		}
163		if modes == 0 {
164			return fmt.Errorf("specify a worker id or one of --all-over, --state, --bead")
165		}
166		if modes > 1 {
167			return fmt.Errorf("specify exactly one of: <worker-id>, --all-over, --state, --bead")
168		}
169	
170		projectRoot := projectFlag
171		if projectRoot == "" {
172			projectRoot = gitpkg.FindProjectRoot(f.WorkingDir)
173		}
174	
175		var targets []string
176		if len(args) > 0 {
177			targets = []string{args[0]}
178		} else {
179			workers := collectAgentWorkers(projectRoot)
180			now := time.Now()
181			for _, wk := range workers {
182				if wk.Kind == "local" {
183					// Local (execute-bead) workers are not reachable through the
184					// server stop endpoint. Skip them here — operators must stop
185					// them via the worktree's own lifecycle.
186					continue
187				}
188				if allOver > 0 {
189					if wk.State != "running" || wk.StartedAt.IsZero() {
190						continue
191					}
192					if now.Sub(wk.StartedAt) <= allOver {
193						continue
194					}
195				}
196				if stateFilter != "" && wk.State != stateFilter {
197					continue
198				}
199				if beadFilter != "" && wk.BeadID != beadFilter {
200					continue
201				}
202				targets = append(targets, wk.ID)
203			}
204		}
205	
206		if len(targets) == 0 {
207			fmt.Fprintln(cmd.OutOrStdout(), "no matching workers")
208			return nil
209		}
210	
211		base := resolveServerURL(projectRoot)
212		client := newLocalServerClient()
213	
214		var firstErr error
215		for _, id := range targets {
216			reqURL := base + "/api/agent/workers/" + id + "/stop"
217			req, err := http.NewRequestWithContext(cmd.Context(), http.MethodPost, reqURL, nil)
218			if err != nil {
219				if firstErr == nil {
220					firstErr = err
221				}
222				continue
223			}
224			resp, err := client.Do(req)
225			if err != nil {
226				fmt.Fprintf(cmd.ErrOrStderr(), "stop %s: %v\n", id, err)
227				if firstErr == nil {
228					firstErr = err
229				}
230				continue
231			}
232			body, _ := io.ReadAll(resp.Body)
233			_ = resp.Body.Close()
234			if resp.StatusCode != http.StatusOK {
235				msg := strings.TrimSpace(string(body))
236				fmt.Fprintf(cmd.ErrOrStderr(), "stop %s: server error (%d): %s\n", id, resp.StatusCode, msg)
237				if firstErr == nil {
238					firstErr = fmt.Errorf("server error (%d) for %s", resp.StatusCode, id)
239				}
240				continue
241			}
242			if asJSON {
243				fmt.Fprintln(cmd.OutOrStdout(), strings.TrimSpace(string(body)))
244			} else {
245				fmt.Fprintf(cmd.OutOrStdout(), "stopping %s\n", id)
246			}
247		}
248		return firstErr
249	}
