251	func (f *CommandFactory) runAgentWorkers(cmd *cobra.Command, _ []string) error {
252		asJSON, _ := cmd.Flags().GetBool("json")
253		watch, _ := cmd.Flags().GetBool("watch")
254		projectFlag, _ := cmd.Flags().GetString("project")
255	
256		projectRoot := projectFlag
257		if projectRoot == "" {
258			projectRoot = gitpkg.FindProjectRoot(f.WorkingDir)
259		}
260	
261		render := func(out io.Writer) error {
262			workers := collectAgentWorkers(projectRoot)
263			if asJSON {
264				enc := json.NewEncoder(out)
265				enc.SetIndent("", "  ")
266				return enc.Encode(workers)
267			}
268			return printAgentWorkersTable(out, workers)
269		}
270	
271		if !watch {
272			return render(cmd.OutOrStdout())
273		}
274	
275		ctx := cmd.Context()
276		for {
277			// Clear screen and move cursor to top-left
278			fmt.Fprint(cmd.OutOrStdout(), "\033[2J\033[H")
279			fmt.Fprintf(cmd.OutOrStdout(), "Workers — %s  (Ctrl-C to stop)\n\n",
280				time.Now().Format("15:04:05"))
281			if err := render(cmd.OutOrStdout()); err != nil {
282				return err
283			}
284			select {
285			case <-ctx.Done():
286				return nil
287			case <-time.After(2 * time.Second):
288			}
289		}
290	}
