292	// collectAgentWorkers fetches workers from the server and local manifest scan,
293	// merges and deduplicates them, and returns the unified list.
294	func collectAgentWorkers(projectRoot string) []agentWorkerDisplay {
295		serverWorkers, serverAttemptIDs := fetchServerAgentWorkers(projectRoot)
296		localWorkers := scanLocalBeadWorkers(projectRoot, serverAttemptIDs)
297	
298		result := make([]agentWorkerDisplay, 0, len(serverWorkers)+len(localWorkers))
299		result = append(result, serverWorkers...)
300		result = append(result, localWorkers...)
301		return result
302	}
