304	// fetchServerAgentWorkers calls GET /api/agent/workers and converts the
305	// response to display records. Returns a set of attempt IDs already covered
306	// by the server so local scanning can skip them.
307	func fetchServerAgentWorkers(projectRoot string) ([]agentWorkerDisplay, map[string]bool) {
308		base := resolveServerURL(projectRoot)
309		client := newLocalServerClient()
310		resp, err := client.Get(base + "/api/agent/workers")
311		if err != nil {
312			return nil, nil
313		}
314		defer resp.Body.Close() //nolint:errcheck
315	
316		var records []agentWorkerServerRecord
317		if err := json.NewDecoder(resp.Body).Decode(&records); err != nil {
318			return nil, nil
319		}
320	
321		out := make([]agentWorkerDisplay, 0, len(records))
