378	// scanLocalBeadWorkers scans .ddx/executions/*/manifest.json and checks
379	// active git worktrees to find locally-running execute-bead executions
380	// not already covered by the server.
381	func scanLocalBeadWorkers(projectRoot string, serverAttemptIDs map[string]bool) []agentWorkerDisplay {
382		execDir := filepath.Join(projectRoot, ".ddx", "executions")
383		entries, err := os.ReadDir(execDir)
384		if err != nil {
385			return nil
386		}
387	
388		active := agentActiveWorktrees(projectRoot)
389	
390		var out []agentWorkerDisplay
391		for _, entry := range entries {
392			if !entry.IsDir() {
393				continue
394			}
395			manifestPath := filepath.Join(execDir, entry.Name(), "manifest.json")
396			data, err := os.ReadFile(manifestPath)
397			if err != nil {
398				continue
399			}
400			var m agentLocalManifest
401			if err := json.Unmarshal(data, &m); err != nil {
402				continue
403			}
404	
405			// Skip if covered by server (attempt already tracked)
406			if serverAttemptIDs[m.AttemptID] {
407				continue
408			}
409			// Skip if worker_id is set — server-submitted executions are in the server list
410			if m.WorkerID != "" {
411				continue
412			}
413	
414			// Check if the worktree for this attempt is still active
415			wtPath := agentLocalWorktreePath(projectRoot, m.BeadID, m.AttemptID)
416			if !active[wtPath] {
417				continue
418			}
419	
420			elapsed := time.Since(m.CreatedAt)
421			d := agentWorkerDisplay{
422				ID:        "local-" + m.AttemptID,
423				Kind:      "local",
424				State:     "running",
425				BeadID:    m.BeadID,
426				BeadTitle: m.Bead.Title,
427				Harness:   m.Requested.Harness,
428				Model:     m.Requested.Model,
429				StartedAt: m.CreatedAt,
430				ElapsedMS: elapsed.Milliseconds(),
431			}
432			out = append(out, d)
433		}
434		return out
435	}
