606	// agentFormatElapsed returns a human-readable elapsed duration like "4m32s".
607	// Uses elapsedMS if positive; otherwise derives from startedAt.
608	func agentFormatElapsed(elapsedMS int64, startedAt time.Time) string {
609		var d time.Duration
610		if elapsedMS > 0 {
611			d = time.Duration(elapsedMS) * time.Millisecond
612		} else if !startedAt.IsZero() {
613			d = time.Since(startedAt)
614			if d < 0 {
615				d = 0
616			}
617		} else {
618			return "-"
619		}
620		h := int(d.Hours())
621		m := int(d.Minutes()) % 60
622		s := int(d.Seconds()) % 60
623		if h > 0 {
624			return fmt.Sprintf("%dh%dm%ds", h, m, s)
625		}
626		if m > 0 {
627			return fmt.Sprintf("%dm%ds", m, s)
628		}
629		return fmt.Sprintf("%ds", s)
630	}
