package agent

import (
	"context"
	"encoding/json"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
)

// DefaultMaxRecoveryCostUSD is the default cap on cumulative reframe+decompose
// spend before the circuit breaker parks the bead to proposed.
const DefaultMaxRecoveryCostUSD = 2.00

// RecoveryFailureClass categorises the persistent failure mode that exhausted
// the escalation ladder, so the PostLadderExhaustionHook can choose the
// appropriate recovery action.
type RecoveryFailureClass string

const (
	// SpecGap is set when the last attempt was blocked by a spec-gap or
	// missing-acceptance review verdict.
	SpecGap RecoveryFailureClass = "spec_gap"
	// TooLarge is set when the last attempt was blocked by a too-large review
	// verdict.
	TooLarge RecoveryFailureClass = "too_large"
	// PersistentExecutionFailed is the default class for all other persistent
	// failures.
	PersistentExecutionFailed RecoveryFailureClass = "persistent_execution_failed"
)

// RecoveryPath indicates which automated recovery action a
// PostLadderExhaustionHook took.
type RecoveryPath string

const (
	Reframe   RecoveryPath = "reframe"
	Decompose RecoveryPath = "decompose"
)

// PostLadderExhaustionResult is the outcome returned by a
// PostLadderExhaustionHook invocation.
type PostLadderExhaustionResult struct {
	Attempted bool
	Succeeded bool
	Path      RecoveryPath
	CostUSD   float64
	// BudgetExhausted is true when recovery budget was exhausted mid-attempt.
	// The caller should NOT park to proposed; let the normal retry flow handle it.
	BudgetExhausted bool
}

// PostLadderExhaustionHook is called when the consecutive_ladder_exhaustions
// counter for a bead reaches the auto-recovery threshold (>= 2). It should
// attempt automated recovery and return the outcome. A nil hook or a result
// with Attempted=false causes the caller to fall through to the existing loop
// path unchanged.
type PostLadderExhaustionHook func(ctx context.Context, beadID string, failureClass RecoveryFailureClass) (*PostLadderExhaustionResult, error)

// deriveRecoveryFailureClass maps the last-attempt report to a
// RecoveryFailureClass for use by the PostLadderExhaustionHook.
func deriveRecoveryFailureClass(report ExecuteBeadReport) RecoveryFailureClass {
	switch {
	case strings.Contains(report.Status, ReviewTerminalClassSpecGap),
		strings.Contains(report.Status, ReviewTerminalClassMissingAcceptance):
		return SpecGap
	case strings.Contains(report.Status, ReviewTerminalClassTooLarge):
		return TooLarge
	default:
		return PersistentExecutionFailed
	}
}

// NewCombinedPostLadderExhaustionHook creates a PostLadderExhaustionHook that
// implements the full two-stage recovery sequence with circuit breaker and
// escape hatch:
//
//   - SpecGap: reframe only; if fails → escape hatch.
//   - TooLarge: decompose only; if fails → escape hatch.
//   - PersistentExecutionFailed: reframe first; if reframe fails, decompose;
//     if both fail → escape hatch.
//
// Circuit breaker: cumulative recovery spend is tracked across invocations.
// Before each invocation, if cumulativeCostUSD >= maxRecoveryCostUSD the
// circuit breaker fires and parks the bead to proposed with reason
// "circuit-breaker". If a single dispatch cost exceeds the remaining budget,
// BudgetExhausted=true is returned and no park-to-proposed is emitted.
//
// Escape hatch: when all applicable paths fail for non-budget reasons, the
// bead is parked to proposed with an "auto-recovery-failed" event and
// reason="both_failed".
func NewCombinedPostLadderExhaustionHook(store ExecuteBeadLoopStore, runner AgentRunner, rcfg config.ResolvedConfig, projectRoot string, maxRecoveryCostUSD float64) PostLadderExhaustionHook {
	if maxRecoveryCostUSD <= 0 {
		maxRecoveryCostUSD = DefaultMaxRecoveryCostUSD
	}

	var mu sync.Mutex
	var cumulativeCostUSD float64

	return func(ctx context.Context, beadID string, failureClass RecoveryFailureClass) (*PostLadderExhaustionResult, error) {
		mu.Lock()
		current := cumulativeCostUSD
		mu.Unlock()

		// Circuit breaker pre-check: fire before any recovery if budget already exhausted.
		if current >= maxRecoveryCostUSD {
			emitAutoRecoveryFailed(store, beadID, "circuit-breaker", current)
			return &PostLadderExhaustionResult{Attempted: true, Succeeded: false}, nil
		}

		remaining := maxRecoveryCostUSD - current

		switch failureClass {
		case SpecGap:
			r := runReframer(ctx, store, runner, rcfg, projectRoot, beadID, remaining)
			mu.Lock()
			cumulativeCostUSD += r.CostUSD
			mu.Unlock()
			if r.BudgetExhausted {
				return &PostLadderExhaustionResult{Attempted: true, Succeeded: false, BudgetExhausted: true}, nil
			}
			if !r.Failed {
				return &PostLadderExhaustionResult{Attempted: true, Succeeded: true, Path: Reframe, CostUSD: r.CostUSD}, nil
			}
			emitAutoRecoveryFailed(store, beadID, "both_failed", cumulativeCostUSD)
			return &PostLadderExhaustionResult{Attempted: true, Succeeded: false}, nil

		case TooLarge:
			r := runDecomposer(ctx, store, runner, rcfg, projectRoot, beadID, remaining)
			mu.Lock()
			cumulativeCostUSD += r.CostUSD
			mu.Unlock()
			if r.BudgetExhausted {
				return &PostLadderExhaustionResult{Attempted: true, Succeeded: false, BudgetExhausted: true}, nil
			}
			if !r.Failed {
				return &PostLadderExhaustionResult{Attempted: true, Succeeded: true, Path: Decompose, CostUSD: r.CostUSD}, nil
			}
			emitAutoRecoveryFailed(store, beadID, "both_failed", cumulativeCostUSD)
			return &PostLadderExhaustionResult{Attempted: true, Succeeded: false}, nil

		case PersistentExecutionFailed:
			// Stage 1: reframe.
			rr := runReframer(ctx, store, runner, rcfg, projectRoot, beadID, remaining)
			mu.Lock()
			cumulativeCostUSD += rr.CostUSD
			remaining = maxRecoveryCostUSD - cumulativeCostUSD
			mu.Unlock()
			if rr.BudgetExhausted {
				return &PostLadderExhaustionResult{Attempted: true, Succeeded: false, BudgetExhausted: true}, nil
			}
			if !rr.Failed {
				return &PostLadderExhaustionResult{Attempted: true, Succeeded: true, Path: Reframe, CostUSD: rr.CostUSD}, nil
			}

			// Circuit breaker check between stages.
			if remaining <= 0 {
				mu.Lock()
				total := cumulativeCostUSD
				mu.Unlock()
				emitAutoRecoveryFailed(store, beadID, "circuit-breaker", total)
				return &PostLadderExhaustionResult{Attempted: true, Succeeded: false}, nil
			}

			// Stage 2: decompose.
			dr := runDecomposer(ctx, store, runner, rcfg, projectRoot, beadID, remaining)
			mu.Lock()
			cumulativeCostUSD += dr.CostUSD
			mu.Unlock()
			if dr.BudgetExhausted {
				return &PostLadderExhaustionResult{Attempted: true, Succeeded: false, BudgetExhausted: true}, nil
			}
			if !dr.Failed {
				return &PostLadderExhaustionResult{Attempted: true, Succeeded: true, Path: Decompose, CostUSD: dr.CostUSD}, nil
			}

			// Both stages failed → escape hatch.
			mu.Lock()
			total := cumulativeCostUSD
			mu.Unlock()
			emitAutoRecoveryFailed(store, beadID, "both_failed", total)
			return &PostLadderExhaustionResult{Attempted: true, Succeeded: false}, nil
		}

		return &PostLadderExhaustionResult{Attempted: false}, nil
	}
}

// emitAutoRecoveryFailed appends the "auto-recovery-failed" event and parks
// the bead to proposed so an operator can intervene.
func emitAutoRecoveryFailed(store ExecuteBeadLoopStore, beadID, reason string, totalCostUSD float64) {
	body, _ := json.Marshal(map[string]any{
		"reason":        reason,
		"total_cost_usd": totalCostUSD,
	})
	_ = store.AppendEvent(beadID, bead.BeadEvent{
		Kind:      "auto-recovery-failed",
		Summary:   reason,
		Body:      string(body),
		Actor:     "ddx agent execute-loop",
		Source:    "ddx agent execute-loop",
		CreatedAt: time.Now().UTC(),
	})
	_ = store.ParkToProposed(beadID, bead.ParkAutoRecoveryFailed, nil)
}

