package agent

import (
	"context"
	"encoding/json"
	"sync/atomic"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent/executeloop"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/escalation"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// makeReframeOutput returns a JSON reframer response that meaningfully changes
// the bead description.
func makeReframeOutput(newDesc string) string {
	out, _ := json.Marshal(map[string]interface{}{
		"description": newDesc,
		"acceptance":  nil,
	})
	return string(out)
}

// makeChildrenOutput returns a JSON decomposer response with two valid children.
func makeChildrenOutput() string {
	children := []map[string]interface{}{
		{
			"title":       "feat(agent): child one",
			"description": "PROBLEM\nChild one.\n\nROOT CAUSE\ncli/internal/agent/foo.go:1.\n",
			"acceptance":  "1. TestChildOne passes\n2. cd cli && go test ./internal/agent/... green\n",
			"labels":      []string{"phase:6"},
		},
		{
			"title":       "feat(agent): child two",
			"description": "PROBLEM\nChild two.\n\nROOT CAUSE\ncli/internal/agent/bar.go:2.\n",
			"acceptance":  "1. TestChildTwo passes\n2. cd cli && go test ./internal/agent/... green\n",
			"labels":      []string{"phase:6"},
		},
	}
	out, _ := json.Marshal(children)
	return string(out)
}

// persistentFailBead creates a bead, pre-seeds the exhaustion counter to 1,
// and returns the bead ID.
func persistentFailBead(t *testing.T, store *bead.Store, id, title string) string {
	t.Helper()
	b := &bead.Bead{
		ID:          id,
		Title:       title,
		Description: "PROBLEM\nTest bead.\n\nROOT CAUSE\ncli/internal/agent/foo.go:1.\n",
		Acceptance:  "1. TestFoo passes\n2. cd cli && go test ./internal/agent/... green\n",
	}
	require.NoError(t, store.Create(b))
	require.NoError(t, incrementConsecutiveLadderExhaustions(store, b.ID))
	return b.ID
}

// persistentFailReport returns an ExecuteBeadReport that triggers the per-bead
// budget exhaustion path (and thus the PostLadderExhaustionHook).
func persistentFailReport(beadID string) ExecuteBeadReport {
	return ExecuteBeadReport{
		BeadID:    beadID,
		Status:    ExecuteBeadStatusExecutionFailed,
		Detail:    escalation.PerBeadBudgetExhaustedReason + ": $1.00 billed >= $0.50 per-bead budget",
		SessionID: "sess-integration-test",
	}
}

// TestReframeFailure_FallsBackToDecompose verifies that for PersistentExecutionFailed,
// when the reframer stub returns Failed=true, the decomposer is called as stage 2.
func TestReframeFailure_FallsBackToDecompose(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	beadID := persistentFailBead(t, store, "ddx-integ-fallback", "reframe-fails-decompose-called")

	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()

	var reframeCalled, decomposeCalled int32

	runner := reframeRunnerFunc(func(opts RunArgs) (*Result, error) {
		if opts.PromptSource == reframerPromptSource {
			atomic.AddInt32(&reframeCalled, 1)
			// Return invalid JSON so reframer fails.
			return &Result{ExitCode: 0, Output: "not-valid-json", CostUSD: 0.10}, nil
		}
		// decomposer call
		atomic.AddInt32(&decomposeCalled, 1)
		cancel()
		return &Result{ExitCode: 0, Output: makeChildrenOutput(), CostUSD: 0.05}, nil
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	hook := NewCombinedPostLadderExhaustionHook(store, runner, rcfg, t.TempDir(), DefaultMaxRecoveryCostUSD)

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, id string) (ExecuteBeadReport, error) {
			return persistentFailReport(id), nil
		}),
	}

	_, _ = worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:                     executeloop.ModeDrain,
		PostLadderExhaustionHook: hook,
		ProjectRoot:              t.TempDir(),
		SessionID:                "sess-fallback",
		WorkerID:                 "worker-fallback",
	})

	assert.EqualValues(t, 1, atomic.LoadInt32(&reframeCalled), "reframer must be called first")
	assert.EqualValues(t, 1, atomic.LoadInt32(&decomposeCalled), "decomposer must be called after reframe fails")
}

// TestBothFail_ParkProposed verifies that when both reframer and decomposer
// stubs return Failed=true for PersistentExecutionFailed, the bead is parked
// to proposed with an "auto-recovery-failed" event with reason="both_failed".
func TestBothFail_ParkProposed(t *testing.T) {
	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	beadID := persistentFailBead(t, store, "ddx-integ-both-fail", "both-fail-park-proposed")

	runner := reframeRunnerFunc(func(opts RunArgs) (*Result, error) {
		// Both reframe and decompose return invalid JSON so both fail.
		return &Result{ExitCode: 0, Output: "invalid-json", CostUSD: 0.01}, nil
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	hook := NewCombinedPostLadderExhaustionHook(store, runner, rcfg, t.TempDir(), DefaultMaxRecoveryCostUSD)

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, id string) (ExecuteBeadReport, error) {
			return persistentFailReport(id), nil
		}),
	}

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	_, _ = worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:                     executeloop.ModeDrain,
		PostLadderExhaustionHook: hook,
		ProjectRoot:              t.TempDir(),
		SessionID:                "sess-both-fail",
		WorkerID:                 "worker-both-fail",
	})

	got, err := store.Get(beadID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusProposed, got.Status, "bead must be parked to proposed when both paths fail")

	events, err := store.Events(beadID)
	require.NoError(t, err)
	var found bool
	for _, ev := range events {
		if ev.Kind == "auto-recovery-failed" {
			found = true
			assert.Contains(t, ev.Summary, "both_failed", "event summary must contain both_failed")
			assert.Contains(t, ev.Body, "both_failed", "event body must contain reason=both_failed")
			assert.Contains(t, ev.Body, "total_cost_usd", "event body must contain total_cost_usd")
		}
	}
	assert.True(t, found, "auto-recovery-failed event must be emitted")
}

// TestRecoveryEvents_StructuredOutput verifies that reframe-applied and
// decompose-applied events include a costUSD field.
func TestRecoveryEvents_StructuredOutput(t *testing.T) {
	t.Run("reframe-applied has cost_usd", func(t *testing.T) {
		store := bead.NewStore(t.TempDir())
		require.NoError(t, store.Init())

		beadID := persistentFailBead(t, store, "ddx-integ-ev-reframe", "event-reframe-cost-usd")

		const newDesc = "PROBLEM\nReframed.\n\nROOT CAUSE\ncli/internal/agent/foo.go:1 updated.\n"
		runner := reframeRunnerFunc(func(opts RunArgs) (*Result, error) {
			return &Result{ExitCode: 0, Output: makeReframeOutput(newDesc), CostUSD: 0.0123}, nil
		})

		cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
		rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

		hook := NewCombinedPostLadderExhaustionHook(store, runner, rcfg, t.TempDir(), DefaultMaxRecoveryCostUSD)

		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
		defer cancel()

		worker := &ExecuteBeadWorker{
			Store: store,
			Executor: ExecuteBeadExecutorFunc(func(_ context.Context, id string) (ExecuteBeadReport, error) {
				cancel()
				return persistentFailReport(id), nil
			}),
		}

		_, _ = worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
			Mode:                     executeloop.ModeDrain,
			PostLadderExhaustionHook: hook,
			ProjectRoot:              t.TempDir(),
			SessionID:                "sess-ev-reframe",
			WorkerID:                 "worker-ev-reframe",
		})

		events, err := store.Events(beadID)
		require.NoError(t, err)
		var found bool
		for _, ev := range events {
			if ev.Kind == "reframe-applied" {
				found = true
				assert.Contains(t, ev.Body, "cost_usd", "reframe-applied event must include cost_usd field")
			}
		}
		assert.True(t, found, "reframe-applied event must be emitted")
	})

	t.Run("decompose-applied has cost_usd", func(t *testing.T) {
		store := bead.NewStore(t.TempDir())
		require.NoError(t, store.Init())

		b := &bead.Bead{
			ID:          "ddx-integ-ev-decompose",
			Title:       "event-decompose-cost-usd",
			Description: "PROBLEM\nToo large.\n\nROOT CAUSE\ncli/internal/agent/big.go:1.\n",
			Acceptance:  "1. TestBig passes\n2. cd cli && go test ./internal/agent/... green\n",
		}
		require.NoError(t, store.Create(b))
		require.NoError(t, incrementConsecutiveLadderExhaustions(store, b.ID))

		runner := reframeRunnerFunc(func(opts RunArgs) (*Result, error) {
			return &Result{ExitCode: 0, Output: makeChildrenOutput(), CostUSD: 0.0456}, nil
		})

		cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
		rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

		hook := NewCombinedPostLadderExhaustionHook(store, runner, rcfg, t.TempDir(), DefaultMaxRecoveryCostUSD)

		ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
		defer cancel()

		worker := &ExecuteBeadWorker{
			Store: store,
			Executor: ExecuteBeadExecutorFunc(func(_ context.Context, id string) (ExecuteBeadReport, error) {
				cancel()
				return ExecuteBeadReport{
					BeadID:    id,
					Status:    ExecuteBeadStatusExecutionFailed + "_" + ReviewTerminalClassTooLarge,
					Detail:    escalation.PerBeadBudgetExhaustedReason + ": $1.00 billed >= $0.50 per-bead budget",
					SessionID: "sess-ev-decompose",
				}, nil
			}),
		}

		_, _ = worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
			Mode:                     executeloop.ModeDrain,
			PostLadderExhaustionHook: hook,
			ProjectRoot:              t.TempDir(),
			SessionID:                "sess-ev-decompose",
			WorkerID:                 "worker-ev-decompose",
		})

		events, err := store.Events(b.ID)
		require.NoError(t, err)
		var found bool
		for _, ev := range events {
			if ev.Kind == "decompose-applied" {
				found = true
				assert.Contains(t, ev.Body, "cost_usd", "decompose-applied event must include cost_usd field")
			}
		}
		assert.True(t, found, "decompose-applied event must be emitted")
	})
}

// TestRecoveryCircuitBreaker_AbortsAtCostCap verifies that the circuit breaker
// fires before the second attempt when cumulative cost reaches the cap.
// The first attempt (reframe stage 1) costs $1.50, which equals the cap.
// Between stages the remaining budget is 0, so circuit breaker fires before
// running stage 2 (decompose). The second runner ($0.60) must never be called.
func TestRecoveryCircuitBreaker_AbortsAtCostCap(t *testing.T) {
	const cap = 1.50

	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	beadID := persistentFailBead(t, store, "ddx-integ-cb", "circuit-breaker-test")

	var decomposeCallCount int32
	runner := reframeRunnerFunc(func(opts RunArgs) (*Result, error) {
		if opts.PromptSource == reframerPromptSource {
			// Reframe fails (invalid JSON) but costs exactly the cap.
			return &Result{ExitCode: 0, Output: "not-json", CostUSD: cap}, nil
		}
		// Decompose would cost $0.60 but must never be reached.
		atomic.AddInt32(&decomposeCallCount, 1)
		return &Result{ExitCode: 0, Output: makeChildrenOutput(), CostUSD: 0.60}, nil
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	hook := NewCombinedPostLadderExhaustionHook(store, runner, rcfg, t.TempDir(), cap)

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, id string) (ExecuteBeadReport, error) {
			cancel()
			return persistentFailReport(id), nil
		}),
	}

	_, _ = worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:                     executeloop.ModeDrain,
		PostLadderExhaustionHook: hook,
		ProjectRoot:              t.TempDir(),
		SessionID:                "sess-cb",
		WorkerID:                 "worker-cb",
	})

	assert.EqualValues(t, 0, atomic.LoadInt32(&decomposeCallCount), "decomposer must not be called when circuit breaker fires")

	got, err := store.Get(beadID)
	require.NoError(t, err)
	assert.Equal(t, bead.StatusProposed, got.Status, "bead must be parked to proposed by circuit breaker")

	events, err := store.Events(beadID)
	require.NoError(t, err)
	var found bool
	for _, ev := range events {
		if ev.Kind == "auto-recovery-failed" {
			found = true
			assert.Contains(t, ev.Summary, "circuit-breaker", "event reason must be circuit-breaker")
			assert.Contains(t, ev.Body, "circuit-breaker")
			assert.Contains(t, ev.Body, "total_cost_usd")
		}
	}
	assert.True(t, found, "auto-recovery-failed event must be emitted with reason=circuit-breaker")
}

// TestPerBeadBudgetExhausted_TriggersAutoRecovery verifies that when the
// recovery dispatch cost exceeds the remaining budget (maxBudgetUSD), the hook
// returns BudgetExhausted=true and does NOT park the bead to proposed — the
// normal per_bead_budget_exhausted path handles it instead.
func TestPerBeadBudgetExhausted_TriggersAutoRecovery(t *testing.T) {
	// maxRecoveryCostUSD is generous so the circuit breaker won't fire.
	// However, the reframe dispatch costs more than the remaining budget,
	// triggering BudgetExhausted.
	const maxCap = 5.0
	const dispatchCost = 6.0 // > maxCap remaining (5.0 - 0 = 5.0)

	store := bead.NewStore(t.TempDir())
	require.NoError(t, store.Init())

	beadID := persistentFailBead(t, store, "ddx-integ-budget-ex", "per-bead-budget-exhausted-test")

	runner := reframeRunnerFunc(func(opts RunArgs) (*Result, error) {
		// Returns cost that exceeds the remaining budget.
		return &Result{ExitCode: 0, Output: "not-json", CostUSD: dispatchCost}, nil
	})

	cfgOpts := config.TestLoopConfigOpts{Assignee: "worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))

	hook := NewCombinedPostLadderExhaustionHook(store, runner, rcfg, t.TempDir(), maxCap)

	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	worker := &ExecuteBeadWorker{
		Store: store,
		Executor: ExecuteBeadExecutorFunc(func(_ context.Context, id string) (ExecuteBeadReport, error) {
			cancel()
			return persistentFailReport(id), nil
		}),
	}

	_, _ = worker.Run(ctx, rcfg, ExecuteBeadLoopRuntime{
		Mode:                     executeloop.ModeDrain,
		PostLadderExhaustionHook: hook,
		ProjectRoot:              t.TempDir(),
		SessionID:                "sess-budget-ex",
		WorkerID:                 "worker-budget-ex",
	})

	// Bead must NOT be parked to proposed — budget exhaustion is handled by
	// the normal per_bead_budget_exhausted flow (bead stays open/unclaimed).
	got, err := store.Get(beadID)
	require.NoError(t, err)
	assert.NotEqual(t, bead.StatusProposed, got.Status, "bead must NOT be parked to proposed on budget exhaustion during recovery")

	// Verify no auto-recovery-failed event was emitted.
	events, err := store.Events(beadID)
	require.NoError(t, err)
	for _, ev := range events {
		assert.NotEqual(t, "auto-recovery-failed", ev.Kind, "auto-recovery-failed must not be emitted on budget exhaustion")
	}
}

